export const DEFAULT_PROJEN_RC_JS_FILENAME = ".projenrc.js";
export const PROJEN_DIR = ".projen";
export const PROJEN_MARKER = "~~ Generated by " + "projen"; // we split into two so /this/ file does not match the marker

/**
 * The current version of the `.projen/tasks.json` manifest schema.
 *
 * Bump this whenever the manifest structure changes in a way the task runtime
 * needs to be aware of. The runtime uses it to detect manifests produced by a
 * newer (potentially incompatible) version of projen. Manifests generated by
 * older versions of projen omit it and are treated as "legacy".
 */
export const TASKS_MANIFEST_VERSION = 2;

export const IS_TEST_RUN = process.env.NODE_ENV === "test";

// eslint-disable-next-line @typescript-eslint/no-require-imports
const packageVersion = require("../package.json").version;

// if we are running with a test, report a fake stable version
export const PROJEN_VERSION = IS_TEST_RUN ? "99.99.99" : packageVersion;
